import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { PieChart } from '@mui/x-charts';
import response from './response.json';

interface CurrentCharge {
  level: number;
  status: string;
  estimatedTimeRemaining: string;
}

interface UsageComponent {
  component: string;
  percentage: number;
}

interface BatteryData {
  currentCharge: CurrentCharge;
  usageBreakdown: UsageComponent[];
}

export default function Widget() {
  const batteryData = response.data as BatteryData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 300, maxWidth: 400, bgcolor: '#303030', color: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              Battery Status
            </Typography>
            <Typography variant="h4" fontWeight={600} sx={{ color: '#03DAC6' }}>
              {batteryData.currentCharge.level}%
            </Typography>
            <Typography variant="caption" sx={{ color: '#FFFFFF' }}>
              {batteryData.currentCharge.status} - {batteryData.currentCharge.estimatedTimeRemaining}
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 1 }}>
              Usage Breakdown
            </Typography>
            <PieChart
              height={120}
              series={[
                {
                  data: batteryData.usageBreakdown.map((item) => ({ id: item.component, value: item.percentage })),
                  colorScale: ['#6200EA', '#03DAC6', '#BB86FC', '#3700B3'],
                },
              ]}
              margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
            />
          </Box>

          <Stack direction="row" spacing={0.5}>
            {batteryData.usageBreakdown.map((item) => (
              <Chip
                key={item.component}
                label={`${item.component}: ${item.percentage}%`}
                sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: '#6200EA', color: '#FFFFFF' }}
              />
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
